body.script:
//
					const slides = document.querySelectorAll('.slide');
					const ind = document.getElementById('ind');
					let cur = 0;

					function show(i) {
						slides[cur].classList.remove('active');
						cur = ((i % slides.length) + slides.length) % slides.length;
						const slide = slides[cur];
						const iframe = slide.querySelector('iframe');
						if (!iframe.dataset.loaded) {
							iframe.src = slide.dataset.src;
							iframe.dataset.loaded = '1';
						}
						slide.classList.add('active');
						ind.textContent = slide.dataset.label;
					}

					show(0);

					document.addEventListener('keydown', e => {
						if (e.key === 'ArrowRight') show(cur + 1);
						else if (e.key === 'ArrowLeft') show(cur - 1);
					});

					let touchX = null;
					const overlay = document.getElementById('swipe-overlay');
					overlay.addEventListener('touchstart', e => {
						touchX = e.touches[0].clientX;
					}, { passive: true });
					overlay.addEventListener('touchend', e => {
						if (touchX === null) return;
						const dx = e.changedTouches[0].clientX - touchX;
						touchX = null;
						if (Math.abs(dx) < 40) return;
						show(dx < 0 ? cur + 1 : cur - 1);
					}, { passive: true });
				//

//
					const cfg              = document.getElementById('cfg').dataset;
					const INSTRUMENT       = cfg.instrument;
					const ASSET            = cfg.asset;
					const MONTHLY_INST     = cfg.monthly || '';
					const REFRESH          = parseInt(cfg.refresh, 10) * 1000;
					const DZ_URL           = '/api/delta-zero/' + INSTRUMENT;
					const MDZ_URL          = MONTHLY_INST ? '/api/delta-zero/' + MONTHLY_INST : '';
					const ADZ_URL          = '/api/delta-zero-all/' + ASSET;
					const DDZ_URL          = '/api/delta-zero-daily/' + ASSET;
					const GL_W_URL         = '/api/gamma-levels/' + INSTRUMENT;
					const GL_M_URL         = MONTHLY_INST ? '/api/gamma-levels/' + MONTHLY_INST : '';
					let   INTERVAL         = '1h';
					const klineUrl   = (iv, limit) => '/api/klines/' + ASSET + '?interval=' + iv + '&limit=' + limit;

					const berlinOffset = (() => {
						const d = new Date();
						const utc = new Date(d.toLocaleString('en-US', { timeZone: 'UTC' }));
						const ber = new Date(d.toLocaleString('en-US', { timeZone: 'Europe/Berlin' }));
						return (ber - utc) / 1000;
					})();

					const chart = LightweightCharts.createChart(document.getElementById('chart-container'), {
						width: window.innerWidth, height: window.innerHeight,
						layout: { background: { type: 'solid', color: '#ffffff' }, textColor: '#333333' },
						grid: { vertLines: { color: '#e8e8e8' }, horzLines: { color: '#e8e8e8' } },
						crosshair: { mode: LightweightCharts.CrosshairMode.Normal },
						rightPriceScale: { borderColor: '#cccccc' },
						timeScale: { borderColor: '#cccccc', timeVisible: true, secondsVisible: false },
						localization: {
							timeFormatter: ts => new Date(ts * 1000).toLocaleString('de-DE', {
								timeZone: 'UTC',
								month: 'short', day: 'numeric',
								hour: '2-digit', minute: '2-digit',
							}),
						},
					});

					window.addEventListener('resize', () => chart.resize(window.innerWidth, window.innerHeight));

					const series = chart.addCandlestickSeries({
						upColor: '#26a69a', downColor: '#ef5350',
						borderVisible: false, wickUpColor: '#26a69a', wickDownColor: '#ef5350',
					});

					let priceLines   = [];
					let monthlyLines = [];
					let allLines     = [];
					let dailyLines   = [];
					let dailyExpiry  = '';

					function clearLines(arr) {
						arr.forEach(pl => series.removePriceLine(pl));
						arr.length = 0;
					}
					let weeklyGammaLines = [];
					let monthlyGammaLines = [];

					function setStatus(text) { document.getElementById('status').textContent = text; }

					function toCandle(k) {
						return { time: Math.floor(k.t / 1000) + berlinOffset, open: parseFloat(k.o), high: parseFloat(k.h), low: parseFloat(k.l), close: parseFloat(k.c) };
					}

					const TF_WINDOW = { '5m': 7, '1h': 30, '4h': 21 };

					function applyVisibleRange() {
						const days = TF_WINDOW[INTERVAL] || 21;
						const now  = Math.floor(Date.now() / 1000) + berlinOffset;
						chart.timeScale().setVisibleRange({
							from: now - days * 86400,
							to:   now + days * 86400 * 0.03,
						});
					}

					async function loadCandles() {
						const resp = await (await fetch(klineUrl(INTERVAL, 500))).json();
						const klines = (resp.result || []).slice().reverse();
						series.setData(klines.map(toCandle));
						applyVisibleRange();
					}

					async function updateLatestCandle() {
						const resp = await (await fetch(klineUrl(INTERVAL, 2))).json();
						const klines = resp.result || [];
						if (!klines.length) return;
						series.update(toCandle(klines[0]));
					}

					async function setTf(iv) {
						INTERVAL = iv;
						document.querySelectorAll('.tf-btn').forEach(b => b.classList.toggle('active', b.textContent === iv));
						await loadCandles();
					}

					async function refreshDeltaZero() {
						const data = await (await fetch(DZ_URL)).json();
						clearLines(priceLines);
						const zeros = [...(data.delta_zero || [])].sort((a, b) => a.price - b.price);
						zeros.forEach(item => priceLines.push(series.createPriceLine({
							price: item.price, color: 'green', lineWidth: 1,
							lineStyle: LightweightCharts.LineStyle.Solid,
							axisLabelVisible: true, title: 'Weekly',
						})));
						if (zeros.length === 2) {
							priceLines.push(series.createPriceLine({
								price: (zeros[0].price + zeros[1].price) / 2, color: 'black', lineWidth: 1,
								lineStyle: LightweightCharts.LineStyle.LargeDashed,
								axisLabelVisible: true, title: 'Middle Weekly',
							}));
						}
						const ts = data.generated_at ? new Date(data.generated_at).toLocaleTimeString() : '—';
						const expiries = [dailyExpiry, INSTRUMENT, MONTHLY_INST].filter(Boolean).join('  ·  ');
						setStatus(expiries + '  ·  ' + (data.trade_count || 0) + ' trades  ·  ' + ts);
					}

					async function refreshMonthlyDeltaZero() {
						if (!MDZ_URL) return;
						const data = await (await fetch(MDZ_URL)).json();
						clearLines(monthlyLines);
						const zeros = [...(data.delta_zero || [])].sort((a, b) => a.price - b.price);
						zeros.forEach(item => monthlyLines.push(series.createPriceLine({
							price: item.price, color: 'blue', lineWidth: 1,
							lineStyle: LightweightCharts.LineStyle.Solid,
							axisLabelVisible: true, title: 'Monthly',
						})));
						if (zeros.length === 2) {
							monthlyLines.push(series.createPriceLine({
								price: (zeros[0].price + zeros[1].price) / 2, color: 'black', lineWidth: 1,
								lineStyle: LightweightCharts.LineStyle.LargeDashed,
								axisLabelVisible: true, title: 'Middle Monthly',
							}));
						}
					}

					async function refreshAllDeltaZero() {
						const data = await (await fetch(ADZ_URL)).json();
						clearLines(allLines);
						const zeros = [...(data.delta_zero || [])].sort((a, b) => a.price - b.price);
						zeros.forEach(item => allLines.push(series.createPriceLine({
							price: item.price, color: 'black', lineWidth: 1,
							lineStyle: LightweightCharts.LineStyle.Solid,
							axisLabelVisible: true, title: 'All',
						})));
						if (zeros.length === 2) {
							allLines.push(series.createPriceLine({
								price: (zeros[0].price + zeros[1].price) / 2, color: 'black', lineWidth: 1,
								lineStyle: LightweightCharts.LineStyle.LargeDashed,
								axisLabelVisible: true, title: 'Middle All',
							}));
						}
					}

					async function refreshDailyDeltaZero() {
						const data = await (await fetch(DDZ_URL)).json();
						dailyExpiry = data.expiry ? (ASSET + '-' + data.expiry) : '';
						clearLines(dailyLines);
						const zeros = [...(data.delta_zero || [])].sort((a, b) => a.price - b.price);
						zeros.forEach(item => dailyLines.push(series.createPriceLine({
							price: item.price, color: 'orange', lineWidth: 1,
							lineStyle: LightweightCharts.LineStyle.Solid,
							axisLabelVisible: true, title: 'Daily 24H',
						})));
						if (zeros.length === 2) {
							dailyLines.push(series.createPriceLine({
								price: (zeros[0].price + zeros[1].price) / 2, color: 'black', lineWidth: 1,
								lineStyle: LightweightCharts.LineStyle.LargeDashed,
								axisLabelVisible: true, title: 'Middle Daily',
							}));
						}
					}

					function drawGammaLines(data, lineStore, lineWidth, prefix) {
						lineStore.forEach(l => series.removePriceLine(l));
						lineStore.length = 0;
						(data.peaks || []).forEach(price => {
							lineStore.push(series.createPriceLine({
								price, color: 'violet', lineWidth,
								lineStyle: LightweightCharts.LineStyle.Solid,
								axisLabelVisible: true, title: prefix + ' GP',
							}));
						});
						(data.bottoms || []).forEach(price => {
							lineStore.push(series.createPriceLine({
								price, color: 'violet', lineWidth,
								lineStyle: LightweightCharts.LineStyle.Solid,
								axisLabelVisible: true, title: prefix + ' GB',
							}));
						});
					}

					async function refreshWeeklyGamma() {
						const data = await (await fetch(GL_W_URL)).json();
						drawGammaLines(data, weeklyGammaLines, 2, 'Weekly');
					}

					async function refreshMonthlyGamma() {
						if (!GL_M_URL) return;
						const data = await (await fetch(GL_M_URL)).json();
						drawGammaLines(data, monthlyGammaLines, 1, 'Monthly');
					}

					let rulerActive = false;
					let rulerPrice1 = null;
					let rulerLines  = [];

					function toggleRuler() {
						rulerActive = !rulerActive;
						document.getElementById('ruler-btn').classList.toggle('active', rulerActive);
						rulerLines.forEach(l => series.removePriceLine(l));
						rulerLines = [];
						rulerPrice1 = null;
						const info = document.getElementById('ruler-info');
						info.style.display = 'none';
						info.textContent = '';
					}

					chart.subscribeClick(param => {
						if (!rulerActive || !param.point) return;
						const price = series.coordinateToPrice(param.point.y);
						if (rulerPrice1 === null) {
							rulerPrice1 = price;
							rulerLines.push(series.createPriceLine({
								price, color: '#555', lineWidth: 1,
								lineStyle: LightweightCharts.LineStyle.Dashed,
								axisLabelVisible: true, title: '①',
							}));
						} else {
							rulerLines.push(series.createPriceLine({
								price, color: '#555', lineWidth: 1,
								lineStyle: LightweightCharts.LineStyle.Dashed,
								axisLabelVisible: true, title: '②',
							}));
							const pct = ((price - rulerPrice1) / rulerPrice1 * 100);
							const sign = pct >= 0 ? '+' : '';
							const info = document.getElementById('ruler-info');
							info.style.display = 'block';
							info.textContent = rulerPrice1.toFixed(0) + ' → ' + price.toFixed(0) + '   ' + sign + pct.toFixed(2) + '%';
							rulerPrice1 = null;
						}
					});

					async function init() {
						try { await loadCandles(); await refreshDeltaZero(); await refreshMonthlyDeltaZero(); await refreshAllDeltaZero(); await refreshDailyDeltaZero(); await refreshWeeklyGamma(); await refreshMonthlyGamma(); }
						catch (e) { setStatus('Error: ' + e.message); }
					}
					function saveChart() {
						const canvases = document.getElementById('chart-container').querySelectorAll('canvas');
						if (!canvases.length) return;
						const w = canvases[0].width, h = canvases[0].height;
						const out = document.createElement('canvas');
						out.width = w; out.height = h;
						const ctx = out.getContext('2d');
						ctx.fillStyle = '#ffffff';
						ctx.fillRect(0, 0, w, h);
						canvases.forEach(c => ctx.drawImage(c, 0, 0));
						const a = document.createElement('a');
						a.href = out.toDataURL('image/png');
						a.download = INSTRUMENT + '_delta_' + new Date().toISOString().slice(0,16).replace('T','_') + '.png';
						a.click();
					}

					init();
					setInterval(updateLatestCandle, 5000);
					setInterval(refreshDeltaZero, REFRESH);
					setInterval(refreshMonthlyDeltaZero, REFRESH);
					setInterval(refreshAllDeltaZero, REFRESH);
					setInterval(refreshDailyDeltaZero, REFRESH);
					setInterval(refreshWeeklyGamma, REFRESH);
					setInterval(refreshMonthlyGamma, REFRESH);
				//
